<?php
declare(strict_types=1);require_once __DIR__.'/_layout.php';$pdo=obtenerConexion();docenteCabecera('Contenidos','contenidos','Publicación de materiales vinculados a cursos asignados.');$docenteId=(int)$GLOBALS['docentePortalId'];docenteSelectorSupervision($pdo);$curso=docenteId($_GET['curso']??0);if($curso)exigirCursoDocente($pdo,$docenteId,$curso);$cursos=cursosDocenteAtenea($pdo,$docenteId);$pa=['d'=>$docenteId];$where=' WHERE c.docente_id=:d';if($curso){$where.=' AND c.asignatura_id=:a';$pa['a']=$curso;}$q=$pdo->prepare('SELECT c.*,a.nombre asignatura FROM contenidos c JOIN asignaturas a ON a.id=c.asignatura_id'.$where.' ORDER BY c.created_at DESC LIMIT 100');$q->execute($pa);$filas=$q->fetchAll();?>
<?php if($docenteId&&$cursos):?><div class="card card-rounded mb-4"><div class="card-body"><h2 class="h5">Nuevo contenido</h2><form method="post" action="contenido_guardar.php" enctype="multipart/form-data" class="row g-3"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="docente_id" value="<?=$docenteId?>"><div class="col-md-5"><label class="form-label">Curso</label><select class="form-select" name="asignatura_id" required><?php foreach($cursos as$c):?><option value="<?=$c['id']?>" <?=$curso===$c['id']?'selected':''?>><?=atenea_e($c['nombre'])?></option><?php endforeach;?></select></div><div class="col-md-7"><label class="form-label">Título</label><input class="form-control" name="titulo" maxlength="190" required></div><div class="col-12"><label class="form-label">Descripción</label><textarea class="form-control" name="descripcion" maxlength="5000"></textarea></div><div class="col-md-6"><label class="form-label">Archivo opcional</label><input class="form-control" type="file" name="archivo" accept=".pdf,.doc,.docx,.ppt,.pptx,.xls,.xlsx,.jpg,.jpeg,.png"></div><div class="col-md-3"><label class="form-label">Estado</label><select class="form-select" name="estado"><option>borrador</option><option>activo</option><option>inactivo</option></select></div><div class="col-md-3 d-flex align-items-end"><button class="btn btn-primary w-100">Guardar contenido</button></div></form><small class="text-muted d-block mt-2">Máximo 10 MB. PDF, documentos Office o imágenes JPG/PNG.</small></div></div><?php endif;?><div class="card card-rounded"><div class="card-body"><div class="table-responsive"><table class="table"><thead><tr><th>Contenido</th><th>Curso</th><th>Archivo</th><th>Estado</th><th>Fecha</th></tr></thead><tbody><?php foreach($filas as$c):?><tr><td><?=atenea_e($c['titulo'])?><small class="d-block text-muted"><?=atenea_e(mb_substr((string)$c['descripcion'],0,100))?></small></td><td><?=atenea_e($c['asignatura'])?></td><td><?php if($c['archivo_relpath']):?><a href="<?=docenteUrl('archivo.php',['tipo'=>'contenido','id'=>$c['id']])?>"><?=atenea_e($c['archivo_nombre'])?></a><?php else:?>—<?php endif;?></td><td><form method="post" action="estado.php" class="d-flex gap-1"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="docente_id" value="<?=$docenteId?>"><input type="hidden" name="tipo" value="contenido"><input type="hidden" name="id" value="<?=$c['id']?>"><select class="form-select form-select-sm" name="estado" aria-label="Estado del contenido"><?php foreach(['borrador','activo','inactivo'] as$estadoOpcion):?><option value="<?=$estadoOpcion?>" <?=$c['estado']===$estadoOpcion?'selected':''?>><?=atenea_e($estadoOpcion)?></option><?php endforeach;?></select><button class="btn btn-sm btn-outline-primary">Aplicar</button><a class="btn btn-sm btn-outline-secondary" href="<?=docenteUrl('contenido_editar.php',['id'=>$c['id']])?>">Editar</a></form></td><td><?=date('d/m/Y',strtotime($c['created_at']))?></td></tr><?php endforeach;?><?php if(!$filas):?><tr><td colspan="5" class="text-center py-5">No hay contenidos reales registrados.</td></tr><?php endif;?></tbody></table></div></div></div><?php docentePie();
